SELECT count(*) FROM movie_info, info_type, title, cast_info, name, role_type, movie_companies, kind_type, char_name WHERE movie_info.info_type_id = info_type.id AND movie_info.movie_id = title.id AND cast_info.movie_id = title.id AND cast_info.person_id = name.id AND cast_info.role_id = role_type.id AND movie_companies.movie_id = title.id AND title.kind_id = kind_type.id AND cast_info.person_role_id = char_name.id;